  return !obj || Object.keys(obj).length === 0;
}

function shouldExcludeFromSnList(item) {
  if (!item || isEmpty(item.json)) return true;

  const materialCode = item.json.material_code || '';
  return materialCode.startsWith("TPVT") || 
         materialCode.startsWith("HSW");
}

