// 获取两个节点的输入数据
const aggregateData = $input.all()[0].json.data; // Aggregate1 节点的数据
const ifData = $('If1').first().json.snList;     // if1 节点的数据

// 创建结果容器
const arrayA = []; // job_number 匹配的项
const arrayB = []; // job_number 不匹配的项

// 创建 Aggregate1 数据的查找表（以 retroid 为键）
const aggregateLookup = {};
aggregateData.forEach(item => {
    aggregateLookup[item.retroid] = item.job_number || item.jobnumber;
});

// 遍历 if1 数据并进行比较
ifData.forEach(item => {
    const sn = item.sn;
    const materialCode = item.material_code;
    const ifJobNumber = item.job_number;

    // 检查是否存在于 Aggregate1 数据中
    if (aggregateLookup.hasOwnProperty(sn)) {
        const aggregateJobNumber = aggregateLookup[sn];

        // 比较 job_number
        if (ifJobNumber === aggregateJobNumber) {
            // 匹配 - 加入数组A
            arrayA.push({
                sn: sn,
                material_code: materialCode
            });
        } else {
            // 不匹配 - 加入数组B
            arrayB.push({
                sn: sn,
                job_number: aggregateJobNumber
            });
        }
    } else {
        // 不存在于 Aggregate1 中 - 根据需求处理（这里加入数组B）
        arrayB.push({
            sn: sn,
            job_number: "Not found in Aggregate1 data"
        });
    }
});

// 确定返回标签
let resultTag;
if (arrayA.length > 0 && arrayB.length > 0) {
    resultTag = "tag1"; // 两者都有值
} else if (arrayA.length > 0 && arrayB.length === 0) {
    resultTag = "tag0"; // 只有matchedItems有值
} else if (arrayA.length === 0 && arrayB.length > 0) {
    resultTag = "tag2"; // 只有mismatchedItems有值
} else {
    resultTag = "tag3"; // 两者都为空（根据需求可以调整）
}

// 返回结果
return [
    {
        json: {
            matchedItems: arrayA,    // 匹配的项
            mismatchedItems: arrayB, // 不匹配的项
            resultTag: resultTag     // 结果标签
        }
    }
];
//tag0代表数据全部正确，tag1代表部份sn的工单号与sap中不符合，tag2代表全部sn的工单号与sap中不符合

// 获取输入数据
const comparisonData =$('查出缓存表工单号不同的数据').first().json; // 包含 matchedItems 和 mismatchedItems 的数据
const jobData =$input.first().json.data ;  // 包含 job_number 和 material_code 的数据

// 创建 job_number 到 material_code 的映射表
const jobMaterialMap = {};
jobData.forEach(item => {
    jobMaterialMap[item.job_number] = item.material_code;
});

// 处理 mismatchedItems，补充 material_code
const processedMismatchedItems = comparisonData.mismatchedItems.map(item => {
    const jobNumber = item.job_number;
    return {
        sn: item.sn,
        job_number: jobNumber,
        material_code: jobMaterialMap[jobNumber] || null // 如果找不到则为 null
    };
});

// 返回结果，保留 matchedItems 不变
return [{
    json: {

        rightmatchedItems: processedMismatchedItems // 补充了 material_code 的数据
    }
}];

